// Código definitivo para retornar 1 legenda_instagram POR ITEM
// Compatível com Run Once for All Items
// À prova de JSON quebrado, markdown, texto puro e variações de output

const items = $input.all();

const outputs = [];

for (const item of items) {
  let raw =
    item.json?.output ??
    item.json?.text ??
    item.json;

  let legenda = '';

  if (!raw) {
    outputs.push({ json: { legenda_instagram: '' } });
    continue;
  }

  // 1️⃣ Se já for objeto
  if (typeof raw === 'object') {
    if (raw.legenda_instagram) {
      legenda = raw.legenda_instagram;
    } else {
      legenda = JSON.stringify(raw);
    }

    outputs.push({
      json: { legenda_instagram: legenda.trim() }
    });
    continue;
  }

  // 2️⃣ Se for string
  if (typeof raw === 'string') {
    let cleaned = raw
      .replace(/```json/gi, '')
      .replace(/```/g, '')
      .trim();

    // tenta extrair JSON interno
    try {
      const match = cleaned.match(/\{[\s\S]*\}/);
      if (match) {
        const parsed = JSON.parse(match[0]);
        if (parsed?.legenda_instagram) {
          legenda = parsed.legenda_instagram;
        } else {
          legenda = cleaned;
        }
      } else {
        legenda = cleaned;
      }
    } catch (e) {
      legenda = cleaned;
    }

    outputs.push({
      json: { legenda_instagram: legenda.trim() }
    });
    continue;
  }

  // fallback extremo
  outputs.push({
    json: { legenda_instagram: '' }
  });
}

return outputs;
